onClick:
{{
  (() => {
    // 1. Valida se o Número da Denúncia foi selecionado no Dropdown
    if (!Oficio_Select_num_denu_autista.selectedOptionValue) {
      return showAlert('Por favor, selecione primeiro o número da denúncia.', 'warning');
    }

    // 2. Valida se o Número do Ofício foi preenchido
    if (!n_oficio_autista.text || n_oficio_autista.text.trim() === "") {
      return showAlert('Por favor, preencha o número do ofício.', 'warning');
    }

    // 3. Valida se a Instituição foi selecionada no Dropdown
    if (!Oficio_Instituicao_autista.selectedOptionValue) {
      return showAlert('Por favor, selecione uma instituição.', 'warning');
    }

    // 4. Se passar em todas as validações, executa a query de salvamento e limpa os campos
    return Query_Salvar_Oficio_Autista.run()
      .then(() => {
        // Lista com absolutamente todos os componentes da tela de Autista
        const camposParaLimpar = [
          "Oficio_Select_num_denu_autista",
          "n_oficio_autista",
          "data_e_hora_denuncia_autista",
          "Oficio_Ident_autista",
          "Oficio_Classificacao_autista",
          "Telefone_Oficio_autista",
          "Oficio_email_autista",
          "Oficio_Denunciante_autista",
          "Oficio_Agressor_autista",
          "Oficio_Testemunha_autista",
          "Oficio_Local_autista",
          "Oficio_Text_den_autista",
          "Oficio_txt_Causa_Autista",
          "Oficio_imagem_autista",
          "data_reg_denuncia_autista",
          "Oficio_hora_reg_autista",
          "Oficio_situacao_autista",
          "Oficio_Instituicao_autista",
          "Oficio_destinatario_autista"
        ];

        // Varre a lista executando o reset assíncrono em cada componente
        camposParaLimpar.forEach(async (campo) => {
          try {
            await resetWidget(campo, true);
          } catch(e) {}
        });

        showAlert('Ofício salvo e todos os campos foram limpos!', 'success');
      })
      .catch((err) => {
        showAlert('Erro ao salvar ofício: ' + err.message, 'error');
      });
  })()
}}
